## HIGH — DRY up duplicated avatar/time helper functions

### What's wrong
`getAvatarColor`, `getInitials`, and `formatRelativeTime` are duplicated in `components/friends-feed-dropdown.tsx` (lines 12-55) and `components/post-comments.tsx` (lines 14-57). A third consumer (the new feed page) is coming.

### What to build

1. Create `lib/social-helpers.ts` with these exports:

```typescript
import type { UserPost } from './types';

export const AVATAR_COLORS = [
  'bg-orange-500', 'bg-emerald-500', 'bg-violet-500', 'bg-sky-500',
  'bg-rose-500', 'bg-amber-500', 'bg-teal-500', 'bg-indigo-500',
];

export function getAvatarColor(username: string): string {
  let hash = 0;
  for (let i = 0; i < username.length; i++) {
    hash = username.charCodeAt(i) + ((hash << 5) - hash);
  }
  return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}

export function getInitials(name: string): string {
  const parts = name.trim().split(/\s+/);
  if (parts.length >= 2) {
    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
  }
  return name.slice(0, 2).toUpperCase();
}

export function formatRelativeTime(dateStr: string): string {
  const now = Date.now();
  const date = new Date(dateStr).getTime();
  const diffSeconds = Math.floor((now - date) / 1000);
  if (diffSeconds < 60) return 'just now';
  const diffMinutes = Math.floor(diffSeconds / 60);
  if (diffMinutes < 60) return `${diffMinutes}m ago`;
  const diffHours = Math.floor(diffMinutes / 60);
  if (diffHours < 24) return `${diffHours}h ago`;
  const diffDays = Math.floor(diffHours / 24);
  if (diffDays < 7) return `${diffDays}d ago`;
  const diffWeeks = Math.floor(diffDays / 7);
  if (diffWeeks < 4) return `${diffWeeks}w ago`;
  const diffMonths = Math.floor(diffDays / 30);
  return `${diffMonths}mo ago`;
}

export function getActionText(post: UserPost): string {
  switch (post.postType) {
    case 'recipe_completed':
      return `completed ${post.recipeTitle ?? 'a recipe'}`;
    case 'photo_upload':
      return `shared a photo of ${post.recipeTitle ?? 'a dish'}`;
    case 'milestone':
      return 'reached a milestone!';
    default:
      return 'did something cool';
  }
}
```

