## MEDIUM — No reusable PWA install logic exists

### What's wrong
No hook exists to detect platform, capture Chrome's `beforeinstallprompt`, track standalone mode, or manage install prompt dismissal. All PWA install UI tasks depend on this shared logic.

### What to build

**`hooks/use-pwa-install.ts`** — Reusable hook:
```ts
'use client'
import { useState, useEffect, useCallback } from 'react'

const DISMISS_KEY = 'cookquest-pwa-dismissed';
const DISMISS_DAYS = 7;

export function usePWAInstall() {
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
  const [isStandalone, setIsStandalone] = useState(false);
  const [isDismissed, setIsDismissed] = useState(false);

  const isIOS = typeof navigator !== 'undefined' && /iphone|ipad|ipod/i.test(navigator.userAgent);
  const isAndroid = typeof navigator !== 'undefined' && /android/i.test(navigator.userAgent);
  const canInstall = !!deferredPrompt; // Chrome/Edge install available

  useEffect(() => {
    // Check standalone mode
    setIsStandalone(
      window.matchMedia('(display-mode: standalone)').matches ||
      (navigator as any).standalone === true
    );

    // Check dismiss timestamp
    const dismissed = localStorage.getItem(DISMISS_KEY);
    if (dismissed) {
      const elapsed = Date.now() - parseInt(dismissed, 10);
      setIsDismissed(elapsed < DISMISS_DAYS * 86400000);
    }

    // Capture Chrome beforeinstallprompt
    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const promptInstall = useCallback(async () => {
    if (!deferredPrompt) return false;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
    return outcome === 'accepted';
  }, [deferredPrompt]);

  const dismiss = useCallback(() => {
    localStorage.setItem(DISMISS_KEY, Date.now().toString());
    setIsDismissed(true);
  }, []);

  const shouldShow = !isStandalone && !isDismissed;

  return { isIOS, isAndroid, isStandalone, canInstall, isDismissed, shouldShow, promptInstall, dismiss };
}
```

Key behaviors:
- `shouldShow` = false if already in standalone mode OR dismissed within 7 days
- `canInstall` = true only when Chrome's `beforeinstallprompt` was captured
- `promptInstall()` triggers native Chrome install dialog
- `dismiss()` saves timestamp to localStorage
- SSR-safe: checks `typeof navigator` before accessing

